"use client";

import { useEffect, useMemo, useState } from "react";

export default function EventCountdown({ targetEpochMs }: { targetEpochMs: number }) {
  const [nowMs, setNowMs] = useState<number | null>(null);

  useEffect(() => {
    setNowMs(Date.now());
    const id = window.setInterval(() => setNowMs(Date.now()), 1000);
    return () => window.clearInterval(id);
  }, []);

  const remaining = useMemo(() => {
    if (nowMs === null) return null;
    const diff = targetEpochMs - nowMs;
    if (diff <= 0) return { done: true, days: 0, hours: 0, minutes: 0, seconds: 0 };

    return {
      done: false,
      days: Math.floor(diff / (1000 * 60 * 60 * 24)),
      hours: Math.floor((diff / (1000 * 60 * 60)) % 24),
      minutes: Math.floor((diff / (1000 * 60)) % 60),
      seconds: Math.floor((diff / 1000) % 60),
    };
  }, [targetEpochMs, nowMs]);

  if (remaining === null) {
    return <div className="text-zinc-500 font-mono text-sm animate-pulse">CALCULATING...</div>;
  }

  if (remaining.done) {
    return (
      <div className="inline-block bg-emerald-500 text-black px-4 py-2 rounded font-black tracking-widest uppercase shadow-[0_0_20px_rgba(16,185,129,0.4)]">
        Live Now
      </div>
    );
  }

  return (
    <div className="flex items-center gap-4 text-center">
      <div className="flex flex-col"><span className="text-4xl font-black font-mono tabular-nums text-emerald-400">{remaining.days}</span><span className="text-[10px] uppercase tracking-widest text-zinc-500 font-bold">Days</span></div>
      <div className="flex flex-col"><span className="text-4xl font-black font-mono tabular-nums text-emerald-400">{remaining.hours}</span><span className="text-[10px] uppercase tracking-widest text-zinc-500 font-bold">Hours</span></div>
      <div className="flex flex-col"><span className="text-4xl font-black font-mono tabular-nums text-emerald-400">{remaining.minutes}</span><span className="text-[10px] uppercase tracking-widest text-zinc-500 font-bold">Mins</span></div>
      <div className="flex flex-col"><span className="text-4xl font-black font-mono tabular-nums text-emerald-400">{remaining.seconds}</span><span className="text-[10px] uppercase tracking-widest text-zinc-500 font-bold">Secs</span></div>
    </div>
  );
}